import json, sys
from docx import Document

# Load employee data
with open('employee_data.json') as f:
    data = json.load(f)

# Load template document
doc = Document('offer_letter_template.docx')

# Replace placeholders
for para in doc.paragraphs:
    for key, value in data.items():
        if f'{{{{{key}}}}}' in para.text:
            para.text = para.text.replace(f'{{{{{key}}}}}', str(value))

# Handle conditional section
if data.get('RELOCATION_PACKAGE') == 'Yes':
    for i, para in enumerate(doc.paragraphs):
        if '{{IF_RELOCATION}}' in para.text:
            start = i
        elif '{{END_IF_RELOCATION}}' in para.text:
            end = i + 1
    doc.paragraphs[start:end] = [p for p in doc.paragraphs[start:end] if '{{IF_RELOCATION}}' not in p.text and '{{END_IF_RELOCATION}}' not in p.text

# Save the filled document
doc.save('/root/offer_letter_filled.docx')
